mapper.select:
SELECT
s.student_id,
s.student_name,
s.class_id,
s.major_id,
s.institute_id,
s.university_id,
s.current_grade,
s.admit_time,
s.graduate_time,
s.academic_status,
s.high_school,
s.home_address,
u.user_id,
u.nickname,
u.email,
u.phone,
u.sex,
u.avatar,
u.user_status,
u.identity,
u.create_time
FROM student s
LEFT JOIN sys_user u ON s.user_id = u.user_id


        AND s.student_id = #{studentId}


        AND s.student_name LIKE CONCAT('%', #{studentName}, '%')


        AND s.class_id = #{classId}


        AND s.major_id = #{majorId}


        AND s.institute_id = #{instituteId}


        AND s.university_id = #{universityId}


        AND s.current_grade = #{currentGrade}


        AND s.admit_time = #{admitTime}


        AND s.graduate_time = #{graduateTime}


        AND s.academic_status = #{academicStatus}


        AND s.high_school LIKE CONCAT('%', #{highSchool}, '%')


        AND s.home_address LIKE CONCAT('%', #{homeAddress}, '%')


        AND u.nickname LIKE CONCAT('%', #{nickname}, '%')


        AND u.email LIKE CONCAT('%', #{email}, '%')


        AND u.phone = #{phone}


        AND u.sex = #{sex}


        AND u.user_status = #{userStatus}


        AND u.identity = #{identity}
